import{_ as t,o as s,c as o,a2 as a}from"./chunks/framework.CKCxdkvf.js";const g=JSON.parse('{"title":"RFC-016 — Spaceflight Fleet · architecture, schema, and dataset boundaries","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-016.md","filePath":"rfc/RFC-016.md"}'),i={name:"rfc/RFC-016.md"};function r(n,e,l,d,c,h){return s(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="rfc-016-—-spaceflight-fleet-·-architecture-schema-and-dataset-boundaries" tabindex="-1">RFC-016 — Spaceflight Fleet · architecture, schema, and dataset boundaries <a class="header-anchor" href="#rfc-016-—-spaceflight-fleet-·-architecture-schema-and-dataset-boundaries" aria-label="Permalink to &quot;RFC-016 — Spaceflight Fleet · architecture, schema, and dataset boundaries&quot;">​</a></h1><p><em>Orrery · Open RFC · v0.2 · May 2026</em></p><blockquote><p><strong>Status:</strong> Draft <strong>Author:</strong> product <strong>Closes into:</strong> ADR-052 (fleet schema + bidirectional cross-reference contract), ADR-053 (mission badge + crew portrait sourcing), ADR-054 (fleet i18n strategy) <strong>Slice gate:</strong> v0.6 <strong>Why this is an RFC:</strong> PRD-012 promises a curated <strong>~110-entry</strong> inventory of the machines used in spaceflight — launchers, crewed spacecraft, cargo spacecraft, stations, rovers, landers, orbiters, observatories — each cross-linked to the existing <code>missions.json</code> / <code>iss-*</code> / <code>tiangong-*</code> / <code>earth-objects</code> / <code>moon-sites</code> / <code>mars-sites</code> data <strong>bidirectionally</strong> (so Apollo 11&#39;s mission panel links to Saturn V on /fleet, and the Gale Crater marker on /mars links to Curiosity on /fleet, and back). The technical questions cluster five ways: <em>schema</em> (per-generation granularity inflates entries; what&#39;s the source-of-truth contract between fleet and the existing datasets?); <em>cross-route bidirectional linking</em> (every primary route gains a <code>fleet_refs</code> field; build-time symmetric validation must catch drift); <em>imagery + crew badges</em> (mission patches and crew portraits per notable flight, plus full hand-authored anatomy SVGs); <em>epoch UI</em> (timeline strip + named-epoch chip filter); <em>i18n + scope discipline</em> (110 entries × 14 locales = 1,540 overlay files at full parity).</p><p><strong>v0.2 additions:</strong> per-generation granularity (Q3 lock); failure entries included (Q5 + &quot;not all about success&quot;); cross-route bidirectional linking (mission ↔ fleet, surface markers ↔ fleet, earth-objects ↔ fleet); epoch timeline + named-epoch chip; full hand-authored SVG anatomy per fleet entry as the headline original contribution. OQ-2 fact error from v0.1 corrected (missions don&#39;t have a structured <code>launch_vehicle</code> field today; <code>fleet_refs</code> migration is locked in instead).</p></blockquote><hr><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Orrery has six hardware datasets today:</p><table tabindex="0"><thead><tr><th>Dataset</th><th>Path</th><th>Records</th><th>Purpose</th></tr></thead><tbody><tr><td><code>rockets.json</code></td><td><code>static/data/rockets.json</code></td><td>13</td><td>Launcher specs (used by <code>/missions</code> and <code>/plan</code>)</td></tr><tr><td><code>iss-modules</code> + <code>iss-visitors</code></td><td><code>static/data/iss-*.json</code> + i18n</td><td>18 + 7</td><td>Pressurised modules + visiting fleet</td></tr><tr><td><code>tiangong-modules</code> + <code>tiangong-visitors</code></td><td><code>static/data/tiangong-*.json</code> + i18n</td><td>3 + 2</td><td>Mirror of the ISS shape</td></tr><tr><td><code>moon-sites.json</code></td><td><code>static/data/moon-sites.json</code></td><td>~20</td><td>Lunar landing sites (rover + lander as <code>payload</code> strings, not first-class)</td></tr><tr><td><code>mars-sites.json</code></td><td><code>static/data/mars-sites.json</code></td><td>~12</td><td>Mars landing sites (similar shape to moon-sites)</td></tr><tr><td><code>earth-objects.json</code></td><td><code>static/data/earth-objects.json</code></td><td>~30</td><td>LEO satellites (Hubble, JWST currently live here as orbital objects)</td></tr></tbody></table><p>Today, &quot;what hardware exists&quot; is fragmented across these six files plus the 36 <code>missions/*</code> records. A user looking for <em>Saturn V</em> finds the launcher in <code>rockets.json</code> and the missions it launched in <code>missions/</code>. A user looking for <em>Curiosity</em> finds the rover encoded as a <code>payload: &quot;Curiosity&quot;</code> string on a Mars site, with no first-class entry. A user looking for <em>Hubble</em> finds it as an <code>earth-objects</code> orbital object. Nothing today gives the unified hardware-inventory view PRD-012 asks for.</p><p>The simplest aggregator is a new <code>fleet.json</code> (with locale overlays) that becomes <em>the canonical hardware-family entry</em> and references the existing data via cross-link IDs. The existing datasets remain authoritative for their scoped purpose — <code>rockets.json</code> keeps its launcher specs that <code>/plan</code> reads at runtime; <code>iss-modules</code> keeps its station-specific module attributes that <code>/iss</code> reads. Fleet entries copy what they need into a flatter schema for the fleet-card grid + detail panel.</p><p>PRD-012&#39;s V1 lock (post-v0.2 update): <strong>~110 curated entries</strong> (per-generation granularity), <strong>crew + badges in V1</strong>, <strong>failure entries included</strong> alongside successes, route at <strong>/fleet</strong> between TIANGONG and SCIENCE in the nav, <strong>bidirectional cross-route linking</strong> with /missions / /moon / /mars / /earth, <strong>epoch timeline strip + named-epoch chip filter</strong>, <strong>hand-authored SVG anatomy per entry</strong> (tiered V1/V1.5/V2 rollout) as the original-content contribution.</p><hr><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><h3 id="oq-1-—-one-unified-fleet-json-vs-per-category-files" tabindex="-1">OQ-1 — One unified <code>fleet.json</code> vs per-category files? <a class="header-anchor" href="#oq-1-—-one-unified-fleet-json-vs-per-category-files" aria-label="Permalink to &quot;OQ-1 — One unified `fleet.json` vs per-category files?&quot;">​</a></h3><p>PRD-012 lists 8 categories. Two structural options:</p><table tabindex="0"><thead><tr><th>Option</th><th>Layout</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>A. Single <code>fleet.json</code></strong> with all 50 entries</td><td>One ~2,000-line file mirroring <code>missions/index.json</code></td><td>Easiest to validate, easiest to filter (single load), matches <code>/missions</code> precedent</td><td>Heterogeneous schema fields per category creep into one document</td></tr><tr><td><strong>B. Per-category files</strong> under <code>static/data/fleet/{category}/{id}.json</code> + <code>fleet/index.json</code></td><td>Mirrors the existing <code>missions/{dest}/{id}.json</code> pattern</td><td>Lets per-category schema variation breathe; smaller files</td><td>More fetches, more validation surface</td></tr><tr><td><strong>C. Single index + per-entry detail</strong> like <code>missions/index.json</code> + <code>missions/mars/curiosity.json</code></td><td>Index has summary fields; detail file has full record</td><td>Lazy-loadable, scales to V2 (~150 entries)</td><td>More files than A, more plumbing than A</td></tr></tbody></table><p><strong>Recommendation: C</strong> — mirror the proven <code>/missions</code> pattern. <code>static/data/fleet/index.json</code> carries the 50-entry summary (id, name, category, agency, era, first-flight year, status, hero-image path, tagline). <code>static/data/fleet/{category}/{id}.json</code> carries the per-entry detail (specs, linked_missions, links, gallery manifest, crew). Locale overlays live at <code>static/data/i18n/{locale}/fleet/{category}/{id}.json</code> — same shape as <code>missions</code>. The category-keyed directory makes new entries discoverable by humans editing the repo.</p><p>This locks into ADR-052 alongside the cross-reference contract.</p><hr><h3 id="oq-2-—-cross-reference-contract-how-do-fleet-entries-link-to-missions-corrected-v0-2" tabindex="-1">OQ-2 — Cross-reference contract: how do fleet entries link to missions? <strong>[CORRECTED v0.2]</strong> <a class="header-anchor" href="#oq-2-—-cross-reference-contract-how-do-fleet-entries-link-to-missions-corrected-v0-2" aria-label="Permalink to &quot;OQ-2 — Cross-reference contract: how do fleet entries link to missions? **[CORRECTED v0.2]**&quot;">​</a></h3><blockquote><p><strong>v0.1 fact error</strong>: claimed missions already had a structured <code>launch_vehicle</code> ID. They don&#39;t — missions only carry a free-text <code>vehicle: &quot;Saturn V (AS-506)&quot;</code> display field. <strong>Corrected below.</strong></p></blockquote><p>A Saturn V fleet entry needs to surface the 13 Apollo + Skylab missions it launched. The MISSIONS tab in the fleet detail panel reads these from the fleet record and renders them as clickable mini-cards. Conversely, <strong>the Apollo 11 mission panel must render</strong> <em>&quot;Hardware: [Saturn V →] [Apollo CSM →] [Apollo LM →]&quot;</em> chips linking back to fleet entries.</p><p><strong>Locked decision: full bidirectional cross-reference via new structured field.</strong></p><h4 id="schema-change" tabindex="-1">Schema change <a class="header-anchor" href="#schema-change" aria-label="Permalink to &quot;Schema change&quot;">​</a></h4><p>Add a new <strong><code>fleet_refs</code></strong> field to the mission base schema (and to moon-sites / mars-sites / earth-objects — see OQ-9 for the cross-route extension):</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> FleetRef</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">id</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">role</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;launcher&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;spacecraft&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;payload&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;station&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> };</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Mission</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">...</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">existing</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> fields</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">fleet_refs</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> FleetRef</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[] };</span></span></code></pre></div><p>Apollo 11 example:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;apollo11&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;fleet_refs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;saturn-v&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;role&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;launcher&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;apollo-csm-block-ii&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;role&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;spacecraft&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;apollo-lm&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;role&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;spacecraft&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  ]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Migration: ~36 mission base files get a hand-curated <code>fleet_refs</code> array (Phase E of Issue #59).</p><h4 id="fleet-side-reverse-pointer" tabindex="-1">Fleet-side reverse pointer <a class="header-anchor" href="#fleet-side-reverse-pointer" aria-label="Permalink to &quot;Fleet-side reverse pointer&quot;">​</a></h4><p>Fleet entries keep <code>linked_missions: [...]</code> as the curated reverse list — used to render the MISSIONS tab in fleet panels.</p><h4 id="build-time-symmetric-check" tabindex="-1">Build-time symmetric check <a class="header-anchor" href="#build-time-symmetric-check" aria-label="Permalink to &quot;Build-time symmetric check&quot;">​</a></h4><p><code>scripts/validate-data.ts</code>:</p><ol><li>Every <code>mission.fleet_refs[*].id</code> must exist in <code>fleet/index.json</code>. (Build fails if not.)</li><li>Every <code>fleet_entry.linked_missions[*]</code> must exist in <code>missions/index.json</code>. (Build fails if not.)</li><li><strong>Bidirectional integrity</strong>: if a mission has <code>fleet_refs</code> containing <code>{id: &quot;saturn-v&quot;, role: &quot;launcher&quot;}</code>, then Saturn V&#39;s <code>linked_missions</code> MUST include that mission. (Build fails on drift.)</li></ol><h4 id="why-bidirectional-in-v1-changed-from-v0-1" tabindex="-1">Why bidirectional in V1 (changed from v0.1) <a class="header-anchor" href="#why-bidirectional-in-v1-changed-from-v0-1" aria-label="Permalink to &quot;Why bidirectional in V1 (changed from v0.1)&quot;">​</a></h4><p>The &quot;see also: Saturn V&quot; affordance from the mission panel is <em>the</em> discovery path users will use to enter /fleet. Deferring to V1.5 leaves /fleet as a one-way cul-de-sac — users find it via nav, not via missions. Bringing it forward to V1 makes /fleet feel native to the rest of the app. The schema cost is small (one new array field on missions); the validation cost is one symmetric loop in validate-data.</p><p>This locks into <strong>ADR-052</strong>.</p><hr><h3 id="oq-3-—-mission-badges-crew-portraits-where-do-they-come-from" tabindex="-1">OQ-3 — Mission badges + crew portraits: where do they come from? <a class="header-anchor" href="#oq-3-—-mission-badges-crew-portraits-where-do-they-come-from" aria-label="Permalink to &quot;OQ-3 — Mission badges + crew portraits: where do they come from?&quot;">​</a></h3><p>PRD-012 V1 includes crew badges + crew portraits for crewed-spacecraft entries. Concrete sourcing:</p><table tabindex="0"><thead><tr><th>Asset</th><th>Source</th><th>Example</th><th>License</th></tr></thead><tbody><tr><td><strong>Mission patches</strong></td><td>Wikimedia Commons (NASA-released originals are PD-USGov; some Roscosmos / CNSA require careful vetting)</td><td>Apollo 11 patch, STS-1 patch, Demo-2 patch</td><td>PD-NASA / Roscosmos-released / CNSA-released</td></tr><tr><td><strong>Crew portraits</strong></td><td>Agency archives (NASA Image Library, ESA Photo Library, JAXA Library, Roscosmos), mirrored via Wikimedia Commons where available</td><td>Yuri Gagarin (Roscosmos archive), Neil Armstrong (NASA), Liu Yang (CMSA)</td><td>PD-USGov for NASA / fair-use risk for non-Western agencies</td></tr></tbody></table><p>The license-vetting pattern is exactly the existing pipeline (ADR-046 / ADR-047): every image gets a row in <code>static/data/image-provenance.json</code>, every license short-name appears in <code>scripts/license-allowlist.ts</code> or in <code>static/data/license-waivers.json</code>, the build fails closed if anything is unattributed.</p><p><strong>Sourcing approach:</strong></p><table tabindex="0"><thead><tr><th>Option</th><th>How</th><th>Trade-off</th></tr></thead><tbody><tr><td><strong>A. Wikimedia-only</strong></td><td>Fetch all imagery via the existing Wikimedia Commons fetch script</td><td>Easiest license vetting; some images may not be on Commons</td></tr><tr><td><strong>B. Agency-first (per ADR-046) with Wikimedia fallback</strong></td><td>Crew portraits prefer agency archives; patches prefer Wikimedia (since patches are typically uploaded there in canonical form)</td><td>Matches imagery-sourcing ADR-046 exactly; one extra agency-API integration per agency</td></tr><tr><td><strong>C. Hand-curated + manual upload to <code>static/images/fleet/</code></strong></td><td>Author selects each image, downloads, attributes, commits</td><td>Most editorial control; most authoring effort</td></tr></tbody></table><p><strong>Recommendation: B</strong> — extend the existing <code>scripts/fetch-assets.ts</code> with a fleet-imagery branch that mirrors the agency-first priority from ADR-046. Crew portraits route through agency archives first (NASA Image Library is well-documented with stable URLs; ESA / JAXA have similar APIs). Patches route through Wikimedia Commons (where official patches are uploaded in canonical form, which is the convention agencies themselves rely on). Failure to find an image at agency/Commons → entry can ship without that image (graceful no-op in the CREW tab, not a build-failure).</p><p>This locks into ADR-053.</p><hr><h3 id="oq-4-—-detail-panel-reuse-vs-new-component" tabindex="-1">OQ-4 — Detail panel reuse vs new component? <a class="header-anchor" href="#oq-4-—-detail-panel-reuse-vs-new-component" aria-label="Permalink to &quot;OQ-4 — Detail panel reuse vs new component?&quot;">​</a></h3><p>PRD-012 §what-it-must-do specifies tabs OVERVIEW / GALLERY / ANATOMY / CREW / MISSIONS / LEARN. The existing <code>StationModulePanel.svelte</code> carries OVERVIEW / GALLERY / ANATOMY / LEARN already. Two new tabs (CREW, MISSIONS) need to be added.</p><table tabindex="0"><thead><tr><th>Option</th><th>Implementation</th></tr></thead><tbody><tr><td><strong>A. Extend <code>StationModulePanel.svelte</code></strong> with conditional CREW + MISSIONS tabs</td><td>Single component, props gate which tabs render. Reuse all existing styling + tab nav</td></tr><tr><td><strong>B. New <code>FleetEntryPanel.svelte</code></strong> copy-pasted from <code>StationModulePanel</code></td><td>Cleaner separation; no risk of breaking <code>/iss</code> or <code>/tiangong</code></td></tr><tr><td><strong>C. Generic <code>EntityDetailPanel.svelte</code></strong> that both stations and fleet use</td><td>Refactor towards a unified component</td></tr></tbody></table><p><strong>Recommendation: B for V1, C as a refactor in v0.7.</strong> Copy <code>StationModulePanel.svelte</code> to <code>FleetEntryPanel.svelte</code> and add the two new tabs. The two existing station panels carry station-specific concerns (microgravity-axes integration, station context links) that don&#39;t apply to a Saturn V fleet entry; cleaner separation now, generalise later when the third use case proves the pattern. A small style-token extraction can land alongside (drawer chrome, tab nav) without committing to a full unified component.</p><p>ANATOMY tab reuses the same SVG schematic infrastructure shipped in May 2026 (the 9 spacecraft diagrams). Fleet entries point to <code>static/diagrams/fleet/{id}.svg</code> if available; tab no-ops if not authored. CREW tab is new — list of mission patches + crew portraits per flight, organised chronologically.</p><p>This locks into the V1 implementation strategy (no ADR needed; component-level decision).</p><hr><h3 id="oq-5-—-i18n-50-entries-×-14-locales-700-overlay-files-same-tiangong-rollout-strategy" tabindex="-1">OQ-5 — i18n: 50 entries × 14 locales = 700 overlay files. Same Tiangong rollout strategy? <a class="header-anchor" href="#oq-5-—-i18n-50-entries-×-14-locales-700-overlay-files-same-tiangong-rollout-strategy" aria-label="Permalink to &quot;OQ-5 — i18n: 50 entries × 14 locales = 700 overlay files. Same Tiangong rollout strategy?&quot;">​</a></h3><p>PRD-011 / Tiangong Explorer rolled out 5 entries × 14 locales = 70 overlay files via auto-translate (DeepL / Claude with human review) per ADR-017 / ADR-033. Fleet is 10× the volume.</p><table tabindex="0"><thead><tr><th>Option</th><th>Scope</th><th>Cost</th></tr></thead><tbody><tr><td><strong>A. en-US only at launch, rely on en-US fallback</strong> (per ADR-017 fallback)</td><td>50 files</td><td>Smallest scope; non-English users see English fleet content</td></tr><tr><td><strong>B. en-US + es</strong> (mirrors existing ADR-017 baseline locales)</td><td>100 files</td><td>2× scope; covers the existing two-locale baseline</td></tr><tr><td><strong>C. All 14 locales</strong> (matches Tiangong / ISS rollout)</td><td>700 files</td><td>14× scope; full i18n parity</td></tr></tbody></table><p><strong>Recommendation: B for V1 launch, C as a follow-up slice.</strong> Ship en-US + es locked-in; the Spanish translation pipeline is well-tested. The remaining 12 locales (de / fr / ja / it / ko / nl / pl / pt / ru / sv / tr / zh) follow in a v0.6.x slice after V1 ships, using the same auto-translate + spot-check pattern as Tiangong (ADR-033). This keeps the V1 surface tight while acknowledging the eventual full-locale parity goal.</p><p>This locks into ADR-054.</p><hr><h3 id="oq-6-—-filter-chip-taxonomy-which-axes" tabindex="-1">OQ-6 — Filter chip taxonomy: which axes? <a class="header-anchor" href="#oq-6-—-filter-chip-taxonomy-which-axes" aria-label="Permalink to &quot;OQ-6 — Filter chip taxonomy: which axes?&quot;">​</a></h3><p>PRD-012 §what-it-must-do specifies CATEGORY / AGENCY / ERA / STATUS chips. Concrete sets:</p><table tabindex="0"><thead><tr><th>Chip</th><th>Values</th></tr></thead><tbody><tr><td><strong>CATEGORY</strong></td><td>launcher / crewed-spacecraft / cargo-spacecraft / station / rover / lander / orbiter / observatory</td></tr><tr><td><strong>AGENCY</strong></td><td>NASA / Roscosmos / ESA / JAXA / CNSA / ISRO / SpaceX / Northrop Grumman / Boeing / multi (e.g., ISS)</td></tr><tr><td><strong>ERA</strong></td><td>1957–1969 (Sputnik–Apollo 11) / 1969–1981 (post-Apollo–Shuttle debut) / 1981–2011 (Shuttle era) / 2011–now (post-Shuttle modern era) / planned</td></tr><tr><td><strong>STATUS</strong></td><td>FLOWN / ACTIVE / RETIRED / PLANNED</td></tr></tbody></table><p>Era boundaries chosen by inflection points (first crewed orbital → first lunar landing → Shuttle debut → Shuttle retirement → modern crewed-commercial era). Not &quot;decades&quot;, because the decades-by-tens cuts cross meaningful technology shifts (Apollo straddles the 60s/70s boundary).</p><p><strong>Recommendation: ship as specified.</strong> No new ADR — these are app-level UX decisions encoded in <code>/fleet/+page.svelte</code>.</p><hr><h3 id="oq-7-—-where-does-fleet-sit-in-the-nav" tabindex="-1">OQ-7 — Where does Fleet sit in the nav? <a class="header-anchor" href="#oq-7-—-where-does-fleet-sit-in-the-nav" aria-label="Permalink to &quot;OQ-7 — Where does Fleet sit in the nav?&quot;">​</a></h3><p>PRD-012 proposes <code>... → MARS → FLEET → SCIENCE</code>. Final order:</p><p><code>EXPLORE → MISSIONS → PLAN → FLY → EARTH → MOON → MARS → ISS → TIANGONG → FLEET → SCIENCE</code></p><p>(Note: per recent commit <code>5833415</code>, ISS / TIANGONG moved to the last menu slots before SCIENCE; FLEET inserts between TIANGONG and SCIENCE so the inventory-style screens cluster: ISS → Tiangong → Fleet → Science.)</p><p><strong>Recommendation: insert between TIANGONG and SCIENCE.</strong> Both stations and Fleet are inventory-shaped pages (cards / detail panels); placing them adjacent groups the catalogue cluster cleanly, with SCIENCE remaining the educational tail.</p><p>This locks into ADR-052 alongside the schema decision.</p><hr><h3 id="oq-8-—-hero-image-strategy-for-the-card-grid" tabindex="-1">OQ-8 — Hero-image strategy for the card grid? <a class="header-anchor" href="#oq-8-—-hero-image-strategy-for-the-card-grid" aria-label="Permalink to &quot;OQ-8 — Hero-image strategy for the card grid?&quot;">​</a></h3><p>110 cards each need a hero photo. The existing <code>/missions</code> grid uses agency-first imagery via ADR-046; same pattern ports.</p><p><strong>Recommendation: reuse the existing pipeline.</strong> <code>static/images/fleet/{id}.jpg</code> resolved at build time via <code>scripts/fetch-assets.ts</code>. Per-image provenance row in <code>image-provenance.json</code> (ADR-047). No new ADR needed.</p><hr><h3 id="oq-9-—-embed-vs-reference-how-do-fleet-entries-relate-to-canonical-hardware-data-already-in-rockets-json-earth-objects-json-moon-sites-json-mars-sites-json" tabindex="-1">OQ-9 — Embed vs reference: how do fleet entries relate to canonical hardware data already in <code>rockets.json</code> / <code>earth-objects.json</code> / <code>moon-sites.json</code> / <code>mars-sites.json</code>? <a class="header-anchor" href="#oq-9-—-embed-vs-reference-how-do-fleet-entries-relate-to-canonical-hardware-data-already-in-rockets-json-earth-objects-json-moon-sites-json-mars-sites-json" aria-label="Permalink to &quot;OQ-9 — Embed vs reference: how do fleet entries relate to canonical hardware data already in `rockets.json` / `earth-objects.json` / `moon-sites.json` / `mars-sites.json`?&quot;">​</a></h3><p>Existing hardware data overlap (PRD-012 §why):</p><ul><li>Saturn V&#39;s specs already in <code>rockets.json</code> (used by /plan).</li><li>Hubble + JWST already in <code>earth-objects.json</code> (used by /earth).</li><li>Curiosity / Perseverance encoded as free-text <code>payload</code> strings on <code>mars-sites.json</code> entries.</li><li>Lunokhod / Apollo LRV likewise encoded on <code>moon-sites.json</code> entries.</li></ul><table tabindex="0"><thead><tr><th>Option</th><th>Layout</th><th>Trade-off</th></tr></thead><tbody><tr><td><strong>A. Reference at runtime</strong></td><td>Fleet entries store IDs only; specs/photos pulled from canonical source at fetch-time. Saturn V&#39;s mass comes from <code>getRocket(&#39;saturn-v&#39;)</code></td><td>Zero drift; more plumbing in <code>data.ts</code> (fleet entry composes from multiple sources)</td></tr><tr><td><strong>B. Embed (copy fields)</strong></td><td>Fleet entries are flat self-contained records. Build-time validator asserts copied fields match source-of-truth (catches drift)</td><td>Lighter at fetch-time; simpler component code; explicit drift check covers correctness</td></tr><tr><td><strong>C. Migrate (fleet replaces overlapping data)</strong></td><td>rockets.json becomes thin /plan-only file (or deleted). Curiosity becomes a fleet entry, removed from mars-sites payload string</td><td>Cleanest long-term; biggest refactor surface</td></tr></tbody></table><p><strong>Locked: B — embed with build-time drift validation.</strong> Fleet records are flat and self-contained. <code>scripts/validate-data.ts</code> extended: for each fleet entry that overlaps a canonical source (e.g., a launcher with a matching <code>rockets.json</code> ID), asserts copied fields match within tolerance. Drift fails the build.</p><p>This locks into <strong>ADR-052</strong>.</p><hr><h3 id="oq-10-—-variant-granularity-family-or-generation" tabindex="-1">OQ-10 — Variant granularity: family or generation? <a class="header-anchor" href="#oq-10-—-variant-granularity-family-or-generation" aria-label="Permalink to &quot;OQ-10 — Variant granularity: family or generation?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Example</th></tr></thead><tbody><tr><td><strong>A. One entry per family</strong></td><td>&quot;Soyuz&quot; = single entry covering 7K-OK → T → TM → TMA → MS (60 years)</td></tr><tr><td><strong>B. One per generation/variant</strong></td><td>&quot;Soyuz 7K-OK&quot;, &quot;Soyuz T&quot;, &quot;Soyuz TM&quot;, &quot;Soyuz TMA&quot;, &quot;Soyuz MS&quot; as separate entries</td></tr><tr><td><strong>C. Family entry + variant timeline tab</strong></td><td>Single Soyuz card with TIMELINE tab showing variants chronologically</td></tr></tbody></table><p><strong>Locked: B — one per generation/variant.</strong> Inflates the entry count from ~50 to ~110 but honours the historical record (Soyuz T flew very different missions than Soyuz MS; Apollo CSM Block I and Block II had different fates). Entry-count budget grew accordingly per Q5.</p><p>Apollo CSM splits into Block II + Skylab CSM + ASTP CSM. Long March splits into 2C / 2F / 3B / 5/5B / 7. Cygnus splits into Standard + Enhanced. Crew Dragon stays single (one variant currently flying). Cargo Dragon splits v1 / v2.</p><p>This locks into <strong>ADR-052</strong> alongside the schema decision.</p><hr><h3 id="oq-11-—-crew-data-scope-per-crewed-spacecraft-entry" tabindex="-1">OQ-11 — Crew data scope per crewed-spacecraft entry <a class="header-anchor" href="#oq-11-—-crew-data-scope-per-crewed-spacecraft-entry" aria-label="Permalink to &quot;OQ-11 — Crew data scope per crewed-spacecraft entry&quot;">​</a></h3><p>PRD-012 V1 includes crew portraits + mission patches for each crewed-spacecraft entry. How many flights?</p><table tabindex="0"><thead><tr><th>Option</th><th>Scope</th></tr></thead><tbody><tr><td><strong>A. Notable-flights curated</strong></td><td>3–6 hand-picked flights per spacecraft (first flight, last flight, 1–4 historic ones). Soyuz: e.g., Soyuz 1 (Komarov), Soyuz 11 (Salyut 1), TM-32 (Tito), MS-25 (recent).</td></tr><tr><td><strong>B. Every flight, paginated</strong></td><td>Soyuz family covers ~150+ flights. Heavy authoring + image-fetch load.</td></tr><tr><td><strong>C. Crew-of-first-flight only</strong></td><td>Single block per spacecraft: inaugural mission&#39;s crew. Smallest scope.</td></tr></tbody></table><p><strong>Locked: A — notable-flights curated.</strong> 3–6 per spacecraft, ~15 crewed entries × ~4 avg = ~60 flight-blocks total. Each block surfaces the mission patch + crew portrait grid + cross-link to that flight&#39;s <code>/missions</code> entry. Manageable scope; reads as &quot;highlights&quot; rather than encyclopedia.</p><p>This locks into <strong>ADR-053</strong>.</p><hr><h3 id="oq-12-—-stations-with-explorer-routes-iss-tiangong-full-panel-or-redirect" tabindex="-1">OQ-12 — Stations with explorer routes (ISS, Tiangong): full panel or redirect? <a class="header-anchor" href="#oq-12-—-stations-with-explorer-routes-iss-tiangong-full-panel-or-redirect" aria-label="Permalink to &quot;OQ-12 — Stations with explorer routes (ISS, Tiangong): full panel or redirect?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>A. Full panel + &quot;Open Explorer →&quot; CTA</strong></td><td>ISS card opens fleet detail panel (specs / gallery / crew / missions / learn). Top of OVERVIEW tab has prominent &quot;Open ISS Explorer →&quot; deep-link to <code>/iss</code>.</td></tr><tr><td><strong>B. Direct redirect (no panel)</strong></td><td>Click ISS card → navigates to <code>/iss</code> immediately, no fleet panel.</td></tr><tr><td><strong>C. Skip from /fleet entirely</strong></td><td>ISS / Tiangong don&#39;t appear on /fleet. Stations category becomes ~4 entries (Salyut 1, Skylab, Mir, Tiangong-1).</td></tr></tbody></table><p><strong>Locked: A — full panel + CTA.</strong> Consistent UX across all 110 cards; the dedicated explorer route is one click away. ISS overview specs (assembly start, mass, orbit, crew complement) live in fleet; deep station-module exploration lives at <code>/iss</code>. No content duplication — fleet&#39;s OVERVIEW tab and /iss serve different reading depths.</p><p>This locks into the V1 implementation strategy.</p><hr><h3 id="oq-13-—-anatomy-svg-authoring-strategy-reuse-path-tiered-rollout" tabindex="-1">OQ-13 — ANATOMY SVG authoring strategy: reuse path + tiered rollout <a class="header-anchor" href="#oq-13-—-anatomy-svg-authoring-strategy-reuse-path-tiered-rollout" aria-label="Permalink to &quot;OQ-13 — ANATOMY SVG authoring strategy: reuse path + tiered rollout&quot;">​</a></h3><p>PRD-012 commits to <strong>hand-authored anatomy SVGs for every fleet entry</strong> in the canonical /science chapter style (white-on-dark, monospace labels, viewBox 400×320, teal accents) — this is the headline original-content contribution that distinguishes /fleet from a Wikipedia-clone catalogue.</p><p><strong>Path</strong>: existing 9 station-visitor SVGs at <code>/diagrams/spacecraft/{id}.svg</code> are reused as-is (mapping fleet IDs to file names). New entries go into the same folder, making <code>/diagrams/spacecraft/</code> the canonical &quot;spacecraft anatomy&quot; location across the app. <strong>No <code>/diagrams/fleet/</code> duplication.</strong></p><p><strong>Tiered rollout</strong>: ~110 SVGs is too much for a single V1. Split into authoring tiers:</p><table tabindex="0"><thead><tr><th>Tier</th><th>When</th><th>Scope</th><th>Approx. count</th></tr></thead><tbody><tr><td><strong>F.1 — Reuse</strong></td><td>V1 (already shipped)</td><td>The 9 station-visitor diagrams</td><td>9</td></tr><tr><td><strong>F.2 — Marquee tier</strong></td><td>V1 launch</td><td>Highest-iconic entries: Saturn V, Shuttle stack, Apollo CSM, Apollo LM, Hubble, JWST, Curiosity, Perseverance, Voyager (1+2 share or split), Cassini, Mir, Salyut 1, ISS, Tiangong, R-7/Vostok, Falcon 9, Crew Dragon (already), Soyuz 7K-OK + Soyuz MS (already), Long March 5, Falcon Heavy, SLS, Lunokhod-1, LRV (Apollo)</td><td>~25–30</td></tr><tr><td><strong>F.3 — Per-category coverage</strong></td><td>V1.5</td><td>Fill in ~5–10 more per category that aren&#39;t yet drawn</td><td>~30</td></tr><tr><td><strong>F.4 — Long tail</strong></td><td>V2</td><td>Remaining ~50 entries (lower-priority orbiters, observatories, smaller landers)</td><td>~40</td></tr></tbody></table><p>V1 ships with F.1 + F.2 = ~35 SVGs. ANATOMY tab no-ops gracefully on entries without an SVG yet (per RFC-016 OQ-4 lock).</p><p>Validation: existing <code>validate-diagrams.ts</code> (chained into validate-data) extends to cover fleet diagrams.</p><p>This locks into the V1 implementation strategy.</p><hr><h3 id="oq-14-—-default-sort-order-on-the-card-grid" tabindex="-1">OQ-14 — Default sort order on the card grid? <a class="header-anchor" href="#oq-14-—-default-sort-order-on-the-card-grid" aria-label="Permalink to &quot;OQ-14 — Default sort order on the card grid?&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Behaviour</th></tr></thead><tbody><tr><td><strong>A. Chronological ascending</strong> (oldest first)</td><td>R-7 (1957) at top, SLS (2022) toward bottom. Reads as a story from Sputnik onward.</td></tr><tr><td><strong>B. Chronological descending</strong> (newest first)</td><td>Falcon 9 / Crew Dragon / Perseverance / JWST at top, historical further down. Page feels current.</td></tr><tr><td><strong>C. Category-grouped</strong></td><td>Cards group under category headers, chronologically within each.</td></tr></tbody></table><p><strong>Locked: B — chronological descending.</strong> Page feels current and relevant on first load. Matches <code>/missions</code> and most card-grid conventions in the app. User can flip to ascending via sort controls if they want the &quot;story from Sputnik&quot; reading.</p><p>This locks into UX-level decision (no ADR).</p><hr><h3 id="oq-15-—-failure-entries-separate-status-or-overlay-on-flown" tabindex="-1">OQ-15 — Failure entries: separate STATUS or overlay on FLOWN? <a class="header-anchor" href="#oq-15-—-failure-entries-separate-status-or-overlay-on-flown" aria-label="Permalink to &quot;OQ-15 — Failure entries: separate STATUS or overlay on FLOWN?&quot;">​</a></h3><p>PRD-012 commits to &quot;every machine, every outcome&quot; — N1, Buran, Schiaparelli, Beresheet, Hakuto-R, Vikram CY-2, Mars 2, Hitomi all included. UX question: where does FAILED sit in the STATUS chip set?</p><table tabindex="0"><thead><tr><th>Option</th><th>STATUS values</th><th>Filter behaviour</th></tr></thead><tbody><tr><td><strong>A. FAILED as separate value</strong></td><td>FLOWN / ACTIVE / RETIRED / FAILED / PLANNED</td><td>User can filter to FAILED to tour the redemption-arc layer of spaceflight history. Most explicit.</td></tr><tr><td><strong>B. FAILED as overlay on FLOWN</strong></td><td>FLOWN+failed-flag / ACTIVE / RETIRED / PLANNED</td><td>Card shows red &quot;FAILED&quot; badge atop FLOWN; filter chips don&#39;t change. Cleaner taxonomy but no &quot;show me only failures&quot; affordance.</td></tr><tr><td><strong>C. PARTIAL-SUCCESS sub-distinction</strong></td><td>Add PARTIAL alongside FAILED for missions like IM-1 (sideways landing, partial success)</td><td>Most granular.</td></tr></tbody></table><p><strong>Locked: A — FAILED as separate STATUS value.</strong> The &quot;tour the failures&quot; reading is exactly what the framing asks for. Card chip shows FAILED in red distinct from FLOWN. PARTIAL-SUCCESS handled inside the editorial copy of those entries (e.g., IM-1&#39;s tagline notes &quot;first US lunar landing since Apollo, sideways orientation&quot;).</p><p>This locks into UX-level decision (no ADR).</p><hr><h3 id="oq-16-—-cross-route-bidirectional-linking-how-far-does-it-reach" tabindex="-1">OQ-16 — Cross-route bidirectional linking: how far does it reach? <a class="header-anchor" href="#oq-16-—-cross-route-bidirectional-linking-how-far-does-it-reach" aria-label="Permalink to &quot;OQ-16 — Cross-route bidirectional linking: how far does it reach?&quot;">​</a></h3><p>PRD-012 commits to fleet becoming the canonical hardware reference. Bidirectional links from:</p><ul><li><strong>Missions</strong> → fleet (via new <code>fleet_refs</code> field, locked in OQ-2)</li><li><strong>Moon-sites</strong> → fleet (which hardware landed at this site)</li><li><strong>Mars-sites</strong> → fleet (which rover/lander operates here)</li><li><strong>Earth-objects</strong> → fleet (Hubble&#39;s earth-objects entry → fleet hubble entry)</li><li><strong>Fleet entries</strong> → all of the above (via reverse <code>linked_sites: [...]</code> array)</li></ul><table tabindex="0"><thead><tr><th>Option</th><th>Scope</th></tr></thead><tbody><tr><td><strong>A. Full bidirectional across all 4 contexts</strong> (locked)</td><td>Each route&#39;s panel renders fleet chip(s); fleet panel renders contextual back-links to /missions / /moon / /mars / /earth</td></tr><tr><td><strong>B. One-way only (mission → fleet)</strong></td><td>Fleet stays a destination, no back-links.</td></tr><tr><td><strong>C. Defer to V1.5</strong></td><td>V1 ships with /fleet alone; cross-links land later.</td></tr></tbody></table><p><strong>Locked: A — full bidirectional across all 4 contexts.</strong> Same <code>fleet_refs: [{id, role}]</code> field on missions / moon-sites / mars-sites / earth-objects entries. Same <code>linked_sites: [...]</code> reverse array on fleet entries. Build-time validator enforces symmetric integrity (drift fails the build).</p><p>This is <strong>Phase K</strong> in the Issue #59 implementation tracker.</p><p>This locks into <strong>ADR-052</strong>.</p><hr><h3 id="oq-18-—-airandspacehistory-com-as-a-first-party-photo-source" tabindex="-1">OQ-18 — <code>airandspacehistory.com</code> as a first-party photo source <a class="header-anchor" href="#oq-18-—-airandspacehistory-com-as-a-first-party-photo-source" aria-label="Permalink to &quot;OQ-18 — `airandspacehistory.com` as a first-party photo source&quot;">​</a></h3><p>Marko owns + operates <strong>airandspacehistory.com</strong>, a curated archive of original museum photography from Russia, USA, UK, France, Germany, Netherlands museums (Smithsonian / Memorial Museum of Cosmonautics / Science Museum London / Musée de l&#39;Air et de l&#39;Espace / Speyer / Aviodrome / etc). Many fleet entries have hardware that&#39;s been photographed in those collections. Including those photos in fleet galleries:</p><ul><li><strong>Adds unique value to /fleet</strong> — first-party museum-grade composition that&#39;s not available on Wikimedia or in agency press kits. Differentiates Orrery&#39;s fleet panels from a Wikipedia-clone catalogue.</li><li><strong>Drives back-traffic to airandspacehistory.com</strong> — each photo links to its source page on the site. Natural cross-promotion of two products in the same author&#39;s portfolio.</li><li><strong>Provenance is straightforward</strong> — Marko is the photographer + site operator; license is &quot;© airandspacehistory.com — used with permission&quot; (self-grant). Goes into <code>static/data/license-waivers.json</code> once with a single explicit waiver row.</li></ul><p><strong>Sourcing priority</strong> (extends ADR-046):</p><ol><li><code>airandspacehistory.com</code> — checked first, used when available</li><li>Agency archives (NASA / ESA / JAXA / Roscosmos / CMSA per ADR-046)</li><li>Wikimedia Commons fallback</li></ol><p><strong>Implementation</strong>:</p><ul><li>Extend <code>scripts/fetch-assets.ts</code> with an <code>airandspacehistory.com</code> branch that scrapes structured photo metadata (title, hardware-id mapping, photo URL, page URL) — needs a small index file or sitemap on the airandspacehistory.com side.</li><li>Each fetched photo lands in <code>static/images/fleet-galleries/{id}/N.jpg</code> with <code>credit: &quot;© airandspacehistory.com&quot;</code> and <code>source_url: &quot;https://airandspacehistory.com/...&quot;</code> in the per-image provenance row.</li><li>Gallery rendering shows credit chip + clickable link to source page.</li></ul><p><strong>Open detail</strong>: format of the airandspacehistory.com sitemap / photo index for the fetcher to consume. Three options:</p><ul><li>A. Custom JSON manifest at <code>https://airandspacehistory.com/orrery-photos.json</code> — cleanest, requires manual curation per photo</li><li>B. RSS / sitemap.xml mining — works automatically but pulls everything</li><li>C. Hand-curate a list in this repo (<code>static/data/airandspacehistory-curation.json</code>) mapping <code>{hardware_id}</code> → <code>[photo URLs]</code> — most explicit; avoids airandspacehistory.com side complexity</li></ul><p><strong>Recommendation: C for V1</strong> (zero cross-site dependency), promote to A in V1.5 if the curation list grows beyond ~50 photos.</p><p>This locks into <strong>ADR-053</strong>.</p><hr><h3 id="oq-17-—-epoch-ui-timeline-strip-named-epoch-chip" tabindex="-1">OQ-17 — Epoch UI: timeline strip + named-epoch chip <a class="header-anchor" href="#oq-17-—-epoch-ui-timeline-strip-named-epoch-chip" aria-label="Permalink to &quot;OQ-17 — Epoch UI: timeline strip + named-epoch chip&quot;">​</a></h3><p>PRD-012 commits to 8 named epochs replacing the original 5-bucket date-range ERA chip:</p><blockquote><p>First Steps · Space Race · Lunar Era · First Stations · Shuttle &amp; Mir · ISS Assembly · Commercial Era · Lunar Return</p></blockquote><table tabindex="0"><thead><tr><th>Option</th><th>UI</th></tr></thead><tbody><tr><td><strong>A. Just rename ERA chip values</strong></td><td>Chip labels become &quot;Lunar Era&quot;, &quot;First Stations&quot;, etc. instead of &quot;1969–1981&quot;. Behaviour unchanged. Simplest.</td></tr><tr><td><strong>B. Named chip + timeline strip</strong> (locked)</td><td>Above the card grid, a horizontal scrub-bar timeline shows the 8 epochs as labelled bands with entry-count tooltips. Click an epoch to filter. Today indicator on the strip. Mobile: collapses to a horizontal swipe carousel.</td></tr><tr><td><strong>C. Pure timeline (no chips)</strong></td><td>Epoch chip removed; timeline strip is the only filter affordance. Cleaner but reduces filter discoverability.</td></tr></tbody></table><p><strong>Locked: B — named chip + timeline strip.</strong> The chip is the persistent filter affordance; the timeline strip is the rich-context overview that shows where the user is on the historical axis. Cards can fade-in/out as the user drags the timeline scrub. Strip is read-only on mobile (tap to filter, no drag).</p><p>This locks into UX-level decision (no ADR).</p><hr><h2 id="decision-criteria" tabindex="-1">Decision criteria <a class="header-anchor" href="#decision-criteria" aria-label="Permalink to &quot;Decision criteria&quot;">​</a></h2><p>We accept the resolution when:</p><ol><li><strong>Schema validates.</strong> <code>validate-data.ts</code> enforces <code>fleet/index.json</code> + per-entry shape; every <code>linked_missions</code> ID resolves to an existing mission; every fleet <code>id</code> referenced from <code>missions[*].launch_vehicle</code> exists in fleet.</li><li><strong>50 cards render.</strong> Card grid loads, filter chips work, deep-link <code>?id=saturn-v</code> opens the detail panel pre-selected.</li><li><strong>Cross-references both ways.</strong> Saturn V&#39;s MISSIONS tab lists the 13 Apollo + Skylab missions; clicking <em>Apollo 11</em> deep-links to <code>/missions?id=apollo11</code> cleanly.</li><li><strong>Crew tab renders for crewed-spacecraft entries</strong> with at least one mission patch + crew portrait per flight (≥10 entries, varying counts of flights each). Provenance complete in <code>image-provenance.json</code>.</li><li><strong>Anatomy tab no-ops gracefully</strong> for entries without an authored SVG (most launchers initially) — UI shows a single placeholder line, not a broken tab.</li><li><strong>i18n parity en-US + es at launch.</strong> Remaining 12 locales tracked in a follow-up issue, ships in a v0.6.x slice.</li><li><strong>Mobile-first.</strong> 375 px width renders without horizontal scroll; bottom-sheet detail panel works as expected.</li><li><strong><code>?view=list</code> fallback</strong> — same ADR-042 pattern. Card grid is plain DOM already, but the contract is consistent.</li><li><strong>Provenance complete.</strong> Every image, every external link recorded in <code>image-provenance.json</code> / link-provenance pipeline (ADR-047 / ADR-051). Fail-closed at build.</li></ol><hr><h2 id="closure-path" tabindex="-1">Closure path <a class="header-anchor" href="#closure-path" aria-label="Permalink to &quot;Closure path&quot;">​</a></h2><ul><li><strong>ADR-052</strong> — Fleet schema + bidirectional cross-reference contract: index + per-entry files under <code>fleet/{category}/{id}.json</code>; new <code>fleet_refs</code> field on missions / moon-sites / mars-sites / earth-objects with symmetric build-time validation; <code>linked_missions</code> + <code>linked_sites</code> reverse arrays on fleet entries; embed-with-drift-check vs the four canonical hardware datasets (rockets, earth-objects, moon-sites, mars-sites); nav slot between TIANGONG and SCIENCE.</li><li><strong>ADR-053</strong> — Imagery sourcing extended: airandspacehistory.com first-party photos with self-grant license waiver, agency-first per ADR-046 (NASA / ESA / JAXA / Roscosmos / CMSA archives), Wikimedia Commons for canonical patches + fallback. Crew portrait scope: 3–6 notable flights per crewed-spacecraft entry.</li><li><strong>ADR-054</strong> — Fleet i18n: en-US + es at V1 launch (~110 entries × 2 = 220 overlay files); remaining 12 locales via the existing ADR-033 auto-translate pipeline in a v0.6.x slice.</li></ul><p><strong>v0.2 locked decisions</strong> (added since v0.1):</p><ul><li>OQ-2 corrected: bidirectional <code>fleet_refs</code> migration on ~36 mission base files, validated symmetrically at build (was: deferred to V1.5).</li><li>OQ-9: embed-with-drift-check against rockets.json / earth-objects.json / moon-sites.json / mars-sites.json (was: not addressed).</li><li>OQ-10: per-generation granularity (was: family-level).</li><li>OQ-11: notable-flights-curated crew scope (was: not addressed).</li><li>OQ-12: full panel + &quot;Open Explorer →&quot; CTA for ISS / Tiangong (was: not addressed).</li><li>OQ-13: hand-authored anatomy SVG per fleet entry, tiered F.1 / F.2 / F.3 / F.4 rollout (was: ~6–8 new SVGs).</li><li>OQ-14: chronological descending default sort (was: chronological ascending).</li><li>OQ-15: FAILED as separate STATUS chip value (was: not addressed; PRD-012 now includes failure entries).</li><li>OQ-16: full bidirectional cross-route linking on /missions / /moon / /mars / /earth (was: deferred to V1.5).</li><li>OQ-17: epoch timeline strip + 8 named-epoch chip (was: 5 date-range buckets only).</li><li>OQ-18: airandspacehistory.com as first-party photo source (was: not addressed).</li></ul><p>Deferred to v0.7+:</p><ul><li>Unified <code>EntityDetailPanel.svelte</code> refactor across stations + fleet (OQ-4 option C).</li><li>Full 14-locale i18n parity (OQ-5 option C).</li><li>F.4 long-tail anatomy SVG completion (Phase F long tail).</li></ul><hr><p><em>Orrery · RFC-016 · v0.2 · Open. Update on closure with the ADR numbers landed.</em></p>',159)])])}const u=t(i,[["render",r]]);export{g as __pageData,u as default};
